// ===============================
// ✅ ОДОБРЕНИЕ НА МПС
// ===============================
function approve_user_vehicle($vehicle_id, $user_id) {

    $users = get_field('assigned_users', $vehicle_id);

    if (!$users) {
        $users = [];
    }

    // ако е ACF user field (обекти)
    $user_ids = [];

    foreach ($users as $u) {
        if (is_object($u)) {
            $user_ids[] = $u->ID;
        } else {
            $user_ids[] = $u;
        }
    }

    // добавяме ако го няма
    if (!in_array($user_id, $user_ids)) {
        $user_ids[] = $user_id;
    }

    update_field('assigned_users', $user_ids, $vehicle_id);

    // махаме заявката
    delete_post_meta($vehicle_id, 'pending_user_' . $user_id);
}

