add_action('admin_menu', function () {
    add_menu_page(
        'Заявки МПС',
        'Заявки МПС',
        'manage_options',
        'vehicle_requests',
        'vehicle_requests_page',
        'dashicons-car',
        25
    );
});

function vehicle_requests_page() {

    echo "<h1>🚗 Заявки за МПС</h1>";

    // ОДОБРЕНИЕ
    if (isset($_GET['approve'])) {
        approve_user_vehicle(intval($_GET['approve']), intval($_GET['user']));
        echo "<div class='notice notice-success'><p>Одобрено!</p></div>";
    }

    // ОТКАЗ
    if (isset($_GET['reject'])) {
        delete_post_meta(intval($_GET['reject']), 'pending_user_' . intval($_GET['user']));
        echo "<div class='notice notice-error'><p>Отказано!</p></div>";
    }

    $vehicles = get_posts([
        'post_type' => 'vehicle',
        'posts_per_page' => -1
    ]);

    foreach ($vehicles as $vehicle) {

        $meta = get_post_meta($vehicle->ID);

        foreach ($meta as $key => $value) {

            if (strpos($key, 'pending_user_') === 0) {

                // 👉 ВЗИМАМЕ ДАННИ
                $data = maybe_unserialize($value[0]);

                if (is_array($data)) {
                    $email = $data['email'] ?? '';
                    $name  = $data['name'] ?? '';
                    $brand = $data['brand'] ?? '';
                    $reg   = $data['reg'] ?? '';
                    $id    = $data['id'] ?? '';
                    $current_user_id = $data['user_id'] ?? 0;
                } else {
                    // 👉 fallback за стари записи
                    $current_user_id = $value[0];
                    $user = get_userdata($current_user_id);

                    $email = $user ? $user->user_email : '';
                    $name  = '';
                    $brand = '';
                    $reg   = '';
                    $id    = get_field('vehicle_id', $vehicle->ID);
                }

                // 👉 fallback ако липсват данни
                if (empty($brand)) {
                    $brand = get_field('marka_prevozno_sredstvo', $vehicle->ID);
                }

                if (empty($reg)) {
                    $reg = get_field('reg_nomer', $vehicle->ID);
                }

                // =========================
                // 🎨 КАРТА
                // =========================
                echo "<div style='background:#fff;padding:15px;margin:15px 0;border-left:5px solid #0073aa;border-radius:6px;'>";

                echo "<p><strong>Имейл:</strong> {$email}</p>";
                echo "<p><strong>Име:</strong> {$name}</p>";
                echo "<p><strong>МПС:</strong> {$reg} {$brand}</p>";
                echo "<p><strong>ID:</strong> {$id}</p>";

                echo "<a href='?page=vehicle_requests&approve={$vehicle->ID}&user={$current_user_id}' 
                        style='margin-right:15px;color:green;font-weight:bold;'>ОДОБРИ</a>";

                echo "<a href='?page=vehicle_requests&reject={$vehicle->ID}&user={$current_user_id}' 
                        style='color:red;font-weight:bold;'>ОТКАЖИ</a>";

                echo "</div>";
            }
        }
    }
}
